package trackerpaths

import (
	"path/filepath"
	"strings"
)

var managedTrackerPathspecs = []string{
	".ddx/beads.jsonl",
	".ddx/beads-archive.jsonl",
	".ddx/metrics/attempts.jsonl",
	".ddx/attachments",
}

// ManagedTrackerPathspecs returns the narrow set of DDx-managed tracker and
// audit paths that concurrent workers may rewrite without blocking pre-claim.
func ManagedTrackerPathspecs() []string {
	return append([]string(nil), managedTrackerPathspecs...)
}

// IsManagedTrackerPath reports whether a repo-relative path is part of the
// narrow DDx-managed tracker/audit set. This intentionally does not widen to
// arbitrary .ddx/** paths.
func IsManagedTrackerPath(path string) bool {
	clean := strings.TrimSpace(filepath.ToSlash(path))
	if clean == "" {
		return false
	}
	for _, managed := range managedTrackerPathspecs {
		m := strings.TrimSuffix(filepath.ToSlash(managed), "/")
		if clean == m || strings.HasPrefix(clean, m+"/") {
			return true
		}
	}
	return false
}

