		".ddx/beads-archive.jsonl",
		".ddx/metrics/attempts.jsonl",
		".ddx/attachments",
	}

	if got := trackerpaths.ManagedTrackerPathspecs(); !reflect.DeepEqual(got, want) {
		t.Fatalf("managed tracker pathspecs = %v, want %v", got, want)
	}

	cases := []struct {
		name string
		path string
	}{
		{name: "beads", path: ".ddx/beads.jsonl"},
		{name: "archive", path: ".ddx/beads-archive.jsonl"},
		{name: "attempts", path: ".ddx/metrics/attempts.jsonl"},
		{name: "attachments", path: ".ddx/attachments/example"},
	}

	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			if !trackerpaths.IsManagedTrackerPath(tc.path) {
				t.Fatalf("shared trackerpaths classifier rejected %q", tc.path)
			}
			if !work.IsTrackerMetadataPath(tc.path) {
				t.Fatalf("pre-claim classifier rejected %q", tc.path)
			}

			r := newLandTestRepo(t)
			r.writeFile(tc.path, "managed tracker content\n")
			r.runGit("add", tc.path)

			blocking, ok := blockingStagedPaths(r.dir)
			if !ok {
				t.Fatalf("blocking staged paths read failed for %q", tc.path)
			}
			if len(blocking) != 0 {
				t.Fatalf("blocking staged paths for %q = %v, want none", tc.path, blocking)
			}
		})
	}
}

